#include "modes/ModeStack.h"
namespace modes { const char* modeName(LexMode m){switch(m){case LexMode::NORMAL:return "NORMAL";case LexMode::LINE_COMMENT:return "LINE_COMMENT";case LexMode::BLOCK_COMMENT:return "BLOCK_COMMENT";case LexMode::STRING:return "STRING";case LexMode::TEMPLATE_TEXT:return "TEMPLATE_TEXT";case LexMode::TEMPLATE_EXPR:return "TEMPLATE_EXPR";}return "UNKNOWN";} ModeStack::ModeStack(LexMode m){stack_.push_back(m);} LexMode ModeStack::current()const{return stack_.back();} void ModeStack::push(LexMode m){stack_.push_back(m);} void ModeStack::pop(){if(stack_.size()>1)stack_.pop_back();} }
